package consul

import (
	"path"
	"time"

	"airwatch/uem/gumdrop-ingestion/pkg/env"
	errorHandling "airwatch/uem/gumdrop-ingestion/pkg/error-handling"
	"airwatch/uem/gumdrop-ingestion/pkg/log"

	consulApiClient "github.com/hashicorp/consul/api"
	json "github.com/json-iterator/go"
	"github.com/pkg/errors"
)

const (
	checkInterval              = time.Second * 5
	consulSessionRenewInterval = time.Second * 5
	consulSessionRenewTtl      = "30s"
)

type Client interface {
	// Address returns the address of the distributed atomic store.
	Address() string

	// RunOnceAction runs an action once on one node, and runs the othersAction on every other node, if specified. The
	// otherActions function will be called once the action function is complete and the lock is released.
	RunOnceAction(ctx *log.Context, name string, action func() error, othersAction func() error) (
		actionChannel <-chan error,
		err error,
	)

	// GetKey gets the value of a consul key.
	GetKey(key string) (*consulApiClient.KVPair, error)

	// PutKey puts the value of a consul key.
	PutKey(key string, value interface{}) error

	// DeleteKey deletes the consul key.
	DeleteKey(key string) error
}

type consulClient struct {
	consulKV      *consulApiClient.KV
	consulTxn     *consulApiClient.Txn
	consulKVPath  string
	consulSession *consulApiClient.Session
	address       string
}

func NewClient(logContext *log.Context) Client {
	logger := log.NewHclLogger(logContext, "consul", log.Level)

	// check a new client
	configWithLogger := consulApiClient.DefaultConfigWithLogger(logger)
	client, err := consulApiClient.NewClient(configWithLogger)
	errorHandling.HandleFatal(logContext, err)

	consulClient := &consulClient{
		consulKV:      client.KV(),
		consulTxn:     client.Txn(),
		consulKVPath:  env.GetValue(logContext, "CONSUL_KV_PATH"),
		consulSession: client.Session(),
		address:       configWithLogger.Address,
	}

	return consulClient
}

func (s *consulClient) Address() string {
	return s.address
}

func (s *consulClient) RunOnceAction(
	logContext *log.Context,
	name string,
	action func() error,
	othersAction func() error,
) (<-chan error, error) {
	const functionName = "consul_client.RunOnceAction"
	var lockName = "oncelock-" + name

	sessionId, done, refresh, err := s.createConsulSession(logContext, name)
	if err != nil {
		return nil, errors.Wrapf(err, "%s: Failed to create consul session '%s'.", functionName, name)
	}

	success, err := s.acquireConsulLock(logContext, sessionId, lockName)
	if err != nil {
		return nil, errors.Wrapf(err, "%s: Failed to acquire consul lock on session '%s'.", functionName, name)
	}

	if success {
		if action != nil {
			go refresh()
			channel := make(chan error)
			go func() {
				if err = action(); err != nil {
					channel <- err
				} else {
					channel <- s.releaseConsulLock(logContext, sessionId, lockName)
				}

				done()
			}()
			return channel, nil
		}
	} else {
		err = s.waitForConsulLockRelease(logContext, sessionId, lockName)
		if err != nil {
			return nil, errors.Wrapf(
				err,
				"%s: Failed to wait for consul lock '%s' release for session '%s'.",
				functionName,
				lockName,
				name,
			)
		}

		if othersAction != nil {
			return nil, othersAction()
		}

		done()
	}

	return nil, nil
}

func (s *consulClient) GetKey(key string) (*consulApiClient.KVPair, error) {
	const functionName = "consul_client.GetKey"
	var consulPath = path.Join(s.consulKVPath, key)

	result, _, err := s.consulKV.Get(
		consulPath,
		&consulApiClient.QueryOptions{},
	)

	return result, errors.Wrap(err, functionName)
}

func (s *consulClient) PutKey(key string, value interface{}) error {
	const functionName = "consul_client.PutKey"

	consulPath := path.Join(s.consulKVPath, key)
	output, err := json.Marshal(value)

	if err != nil {
		return errors.Wrap(err, functionName)
	}

	_, err = s.consulKV.Put(
		&consulApiClient.KVPair{
			Key:   consulPath,
			Value: output,
		},
		nil,
	)

	return errors.Wrap(err, functionName)
}

func (s *consulClient) DeleteKey(key string) error {
	const functionName = "consul_client.DeleteKey"

	_, err := s.consulKV.Delete(path.Join(s.consulKVPath, key), nil)

	return errors.Wrap(err, functionName)
}

func (s *consulClient) createConsulSession(ctx *log.Context, name string) (string, func(), func(), error) {
	entry := &consulApiClient.SessionEntry{
		Name: name,
		TTL:  consulSessionRenewTtl,
	}

	log.Infow(ctx, "Creating consul session.", "session_name", name)

	sessionId, _, err := s.consulSession.Create(entry, nil)

	if err != nil {
		return "", nil, nil, errors.Wrapf(err, "Faild to create consul session '%s'.", name)
	}

	consulTimer := time.NewTicker(consulSessionRenewInterval)
	quitRefresh := make(chan bool)

	refresh := func() {
		for {
			select {
			case <-consulTimer.C:
				log.Infow(
					ctx, "Renewing consul session.",
					"session_name", name,
					"session_id", sessionId,
				)

				_, _, err = s.consulSession.Renew(sessionId, nil)
				err = errorHandling.HandleWarning(ctx, errors.Wrapf(err, "Failed to renew consul session '%s'.", name))

				if err == nil {
					log.Infow(
						ctx, "Renewed consul session.",
						"session_name", name,
						"session_id", sessionId,
					)
				}
			case <-quitRefresh:
				log.Infow(
					ctx,
					"Terminating refresh loop for consul session.",
					"session_name", name,
					"session_id", sessionId,
				)
				consulTimer.Stop()
				log.Infow(
					ctx,
					"Terminated refresh loop for consul session.",
					"session_name", name,
					"session_id", sessionId,
				)
				return
			}
		}
	}

	done := func() {
		quitRefresh <- true
		close(quitRefresh)

		log.Infow(ctx, "Destroying consul session.", "session_name", name)

		_, err = s.consulSession.Destroy(sessionId, nil)
		_ = errorHandling.HandleWarning(ctx, errors.Wrapf(err, "Failed to destroy consul session '%s'.", name))
	}

	return sessionId, done, refresh, nil
}

func (s *consulClient) acquireConsulLock(ctx *log.Context, sessionId string, key string) (bool, error) {
	kvPair := &consulApiClient.KVPair{
		Key:     path.Join(s.consulKVPath, key),
		Session: sessionId,
	}

	log.Infow(ctx, "Acquiring consul lock.", "session_id", sessionId, "consul_key", key)

	success, _, err := s.consulKV.Acquire(kvPair, nil)
	if err != nil {
		return false, errors.Wrapf(
			err,
			"Failed to acquire lock for consul session %s with key %s. False returned from release api.",
			sessionId,
			key,
		)
	}

	if success {
		log.Infow(
			ctx,
			"Acquired consul lock.",
			"session_id", sessionId,
			"consul_key", key,
		)
	} else {
		log.Infow(
			ctx,
			"Failed to acquired consul lock.",
			"session_id", sessionId,
			"consul_key", key,
		)
	}

	return success, nil
}

func (s *consulClient) releaseConsulLock(ctx *log.Context, sessionId string, key string) error {
	consulKey := path.Join(s.consulKVPath, key)

	log.Infow(ctx, "Releasing consul lock.", "session_id", sessionId, "consul_key", key)

	ops := consulApiClient.TxnOps{
		&consulApiClient.TxnOp{
			KV: &consulApiClient.KVTxnOp{
				Verb:    consulApiClient.KVUnlock,
				Key:     consulKey,
				Session: sessionId,
			},
		},
		&consulApiClient.TxnOp{
			KV: &consulApiClient.KVTxnOp{
				Verb: consulApiClient.KVDelete,
				Key:  consulKey,
			},
		},
	}

	success, _, _, err := s.consulTxn.Txn(ops, nil)
	if err != nil {
		return errors.Wrapf(
			err,
			"Failed to release lock for consul session %s with key %s. False returned from release api.",
			sessionId,
			key,
		)
	}

	if !success {
		return errors.Errorf(
			"Failed to release lock for consul session %s with key %s. False returned from release api.",
			sessionId,
			key,
		)
	}

	return nil
}

func (s *consulClient) waitForConsulLockRelease(ctx *log.Context, sessionId string, key string) error {
	const functionName = "consul_client.waitForConsulLockRelease"

	consulTimer := time.NewTicker(checkInterval)
	defer consulTimer.Stop()

	for ; true; <-consulTimer.C {
		result, err := s.GetKey(key)

		if err != nil {
			return errors.Wrap(err, functionName)
		} else if result != nil && result.Session != "" {
			log.Infow(
				ctx,
				"Waiting for lock release for consul session.",
				"session_id",
				sessionId,
				"consul_key",
				key,
				"error",
				err,
			)
		} else {
			return nil
		}
	}

	return nil
}
